const collection = $('Normalize Data').item.json.config.collection_name;

async function fetchWithTimeout(url, options, timeoutMs = 30000) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const response = await fetch(url, { ...options, signal: controller.signal });
    clearTimeout(timer);
    return response;
  } catch (err) {
    clearTimeout(timer);
    if (err.name === 'AbortError') throw new Error(`Timeout after ${timeoutMs}ms calling ${url}`);
    throw err;
  }
}

try {
  // Step 1: Generate embedding via OpenAI (30s timeout)
  const embResponse = await fetchWithTimeout('https://api.openai.com/v1/embeddings', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${OPENAI_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: 'text-embedding-3-small',
      input: query
    })
  }, 30000);
  const embData = await embResponse.json();

  if (!embData.data || !embData.data[0]) {
    return 'Error generando embedding: ' + JSON.stringify(embData);
  }
  const vector = embData.data[0].embedding;

  // Step 2: Search Qdrant (30s timeout)
  const searchResponse = await fetchWithTimeout(`${QDRANT_URL}/collections/${collection}/points/search`, {
    method: 'POST',
    headers: {
      'api-key': QDRANT_KEY,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      vector: vector,
      limit: 10,
      with_payload: true,
      score_threshold: 0.3
    })
  }, 30000);
  const searchData = await searchResponse.json();

  const results = (searchData.result || []);
  if (results.length === 0) {
    return 'No se encontraron resultados relevantes en la base de conocimientos.';
  }

  const texts = results.map(r => {
    const text = r.payload?.text || r.payload?.content || '';
    const source = r.payload?.source || 'unknown';
    const score = r.score?.toFixed(2) || '?';
    return `[${source} score:${score}] ${text}`;
  }).filter(t => t.length > 30);

  return texts.join('\n\n---\n\n');
} catch (error) {
  return 'Error buscando en base de conocimientos: ' + error.message;
}
